const isWebhook = $json.body !== undefined;
const periodoFromBody = $json.body?.periodo;
const today = new Date();
const isFirstOfMonth = today.getDate() === 1;
const periodo = periodoFromBody || (isFirstOfMonth ? 'mensile' : 'settimanale');
const days = periodo === 'mensile' ? 30 : 7;
const since = new Date(Date.now() - days * 86400000).toISOString().split('T')[0];
return [{ json: { periodo, days, since, dataAudit: today.toISOString().split('T')[0] } }];

const brand = ($('Read BRAND').first().json[0]) || {};
const contenuti = $('Read CALENDARIO').first().json || [];
const logs = $('Read LOG').first().json || [];
const p = $('Determine Period').first().json;
return [{ json: { brand, contenuti, logs, periodo: p.periodo, days: p.days, dataAudit: p.dataAudit } }];

const txt = $json.content?.[0]?.text || '';
const m = txt.match(/\{[\s\S]*\}/);
if (!m) throw new Error('No JSON');
const parsed = JSON.parse(m[0]);
return [{ json: parsed }];
